import React, { useState } from "react";
import Sidebar from "./components/Sidebar";
import Dashboard from "./components/Dashboard";
import Classrooms from "./components/classsection/Classrooms";
import Events from "./components/Events";
import Detail from "./components/Details";
import Settings from "./components/Settings";
import "./App.css";

// Simple UserProfile modal component
function UserProfileModal({ open, onClose, userName }) {
  if (!open) return null;
  return (
    <div className="profile-modal-overlay" onClick={onClose}>
      <div className="profile-modal" onClick={(e) => e.stopPropagation()}>
        <h2>User Profile</h2>
        <div style={{ margin: "20px 0" }}>
          <div
            style={{
              width: 64,
              height: 64,
              borderRadius: "50%",
              background: "#eee",
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              fontSize: 32,
              margin: "0 auto",
            }}
          >
            {userName.charAt(0).toUpperCase()}
          </div>
          <div style={{ marginTop: 16, textAlign: "center" }}>
            <strong>{userName}</strong>
          </div>
        </div>
        <button
          onClick={onClose}
          className="dashboard-btn"
          style={{ width: "100%" }}
        >
          Close
        </button>
      </div>
    </div>
  );
}

function App() {
  const [selectedPage, setSelectedPage] = useState("dashboard");
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const [sidebarMobile, setSidebarMobile] = useState(false);
  const [profileOpen, setProfileOpen] = useState(false);

  // You can replace this with actual user data
  const userName = "Rajeshwaran";

  return (
    <div className="app-container">
      <Sidebar
        onSelectPage={setSelectedPage}
        open={sidebarOpen}
        mobileOpen={sidebarMobile}
        setOpen={setSidebarOpen}
        setMobileOpen={setSidebarMobile}
        className={sidebarMobile ? "sidebar sidebar-active" : "sidebar"}
      />
      <div className={`main-content${sidebarMobile ? " content-shift" : ""}`}>
        <header className="header">
          <div className="header__left">
            <h2>Welcome, {userName}</h2>
          </div>
          <div className="header__right">
            <span className="material-icons header__icon">notifications</span>
            <span
              className="material-icons header__icon"
              style={{ cursor: "pointer" }}
              onClick={() => setProfileOpen(true)}
              title="Profile"
            >
              account_circle
            </span>
          </div>
        </header>
        <div className="content">
          {selectedPage === "dashboard" && <Dashboard />}
          {selectedPage === "classrooms" && <Classrooms />}
          {selectedPage === "events" && <Events />}
          {selectedPage === "details" && <Detail />}
          {selectedPage === "settings" && <Settings />}
        </div>
      </div>
      <UserProfileModal
        open={profileOpen}
        onClose={() => setProfileOpen(false)}
        userName={userName}
      />
    </div>
  );
}

export default App;

/* Add this CSS to App.css or a global stylesheet for the modal: */
